imaw_pipeline.abstract_schema:
{
  "entities": [
    "System Manager",
    "API Gateway",
    "State Datastore",
    "Assignment Unit",
    "State Regulator",
    "Execution Node",
    "Node Agent",
    "Deployable Unit"
  ],
  "relationships": [
    {
      "source_entity": "System Manager",
      "target_entity": "Execution Node",
      "interaction": "manages and oversees"
    },
    {
      "source_entity": "API Gateway",
      "target_entity": "System Manager",
      "interaction": "exposes the interface for"
    },
    {
      "source_entity": "System Manager",
      "target_entity": "State Datastore",
      "interaction": "uses as a persistent backing store for all configuration and state data"
    },
    {
      "source_entity": "Assignment Unit",
      "target_entity": "API Gateway",
      "interaction": "observes for newly created, unassigned Deployable Units"
    },
    {
      "source_entity": "Assignment Unit",
      "target_entity": "Execution Node",
      "interaction": "selects a target for a Deployable Unit"
    },
    {
      "source_entity": "State Regulator",
      "target_entity": "System Manager",
      "interaction": "runs processes to maintain the desired system state"
    },
    {
      "source_entity": "Execution Node",
      "target_entity": "Deployable Unit",
      "interaction": "provides the runtime environment for"
    },
    {
      "source_entity": "Node Agent",
      "target_entity": "Execution Node",
      "interaction": "runs on and manages"
    },
    {
      "source_entity": "Node Agent",
      "target_entity": "Deployable Unit",
      "interaction": "ensures contained components are running as specified"
    }
  ],
  "rules": [
    "The Assignment Unit cannot place a Deployable Unit on an Execution Node if the node lacks the required resources.",
    "A Deployable Unit is the smallest manageable and executable component in the system.",
    "Each Execution Node must run a Node Agent to communicate with the System Manager.",
    "All system state and configuration data must be stored in the State Datastore.",
    "All external and internal component interactions with the System Manager must occur through the API Gateway."
  ]
}

imaw_pipeline.isomorphic_mapping:
{
  "entity_mappings": [
    {
      "abstract_entity": "System Manager",
      "metaphorical_entity": "Head Concierge"
    },
    {
      "abstract_entity": "API Gateway",
      "metaphorical_entity": "Front Desk"
    },
    {
      "abstract_entity": "State Datastore",
      "metaphorical_entity": "Master Ledger"
    },
    {
      "abstract_entity": "Assignment Unit",
      "metaphorical_entity": "Head of Staff"
    },
    {
      "abstract_entity": "State Regulator",
      "metaphorical_entity": "Head Housekeeper"
    },
    {
      "abstract_entity": "Execution Node",
      "metaphorical_entity": "Guest Suite"
    },
    {
      "abstract_entity": "Node Agent",
      "metaphorical_entity": "Suite Butler"
    },
    {
      "abstract_entity": "Deployable Unit",
      "metaphorical_entity": "Guest Party"
    }
  ],
  "translated_rules": [
    "The Head of Staff cannot place a Guest Party in a Guest Suite if the suite lacks the required amenities.",
    "A Guest Party is the smallest manageable and serviceable unit in the hotel.",
    "Each Guest Suite must have an assigned Suite Butler to communicate with the Head Concierge.",
    "All hotel state and configuration data must be recorded in the Master Ledger.",
    "All interactions from guests or staff with the Head Concierge must occur through the Front Desk."
  ]
}
